// MFA Backup Codes Controller
@RestController
@RequestMapping("/api/users")
public class MfaBackupCodesController {
    @Autowired
    private MfaBackupCodesService mfaBackupCodesService;

    @PutMapping("/{id}/enable-mfa")
    public ResponseEntity<?> enableMfa(@PathVariable Long id) {
        User user = userRepository.findById(id).orElseThrow();
        if (!user.getEnabledMfa()) {
            List<String> recoveryCodes = new ArrayList<>();
            for (int i = 0; i < 10; i++) {
                recoveryCodes.add(mfaBackupCodesService.generateRandomCode());
            }
            user.setMfaRecoveryCodes(recoveryCodes);
            userRepository.save(user);
        }
        return ResponseEntity.ok("MFA enabled successfully");
    }

    @PostMapping("/{id}/verify-backup-code")
    public ResponseEntity<?> verifyBackupCode(@PathVariable Long id, @RequestBody String code) {
        User user = userRepository.findById(id).orElseThrow();
        if (mfaBackupCodesService.verifyBackupCode(user, code)) {
            return ResponseEntity.ok("Backup code verified successfully");
        } else {
            return ResponseEntity.badRequest().body("Invalid backup code");
        }
    }
}

